SELECT id, tenant_id, hour_start, root_hash, log_count, created_at
FROM audit.audit_root_hash
WHERE tenant_id = #{tenantId} AND hour_start = #{hourStart}

SELECT COUNT(*)
FROM audit.audit_log
WHERE tenant_id = #{tenantId} AND created_at >= #{hourStart}

SELECT id, tenant_id, user_id, username, operation, target_type, target_id, target_name,
       ip_address, user_agent, status, error_message, log_hash, previous_hash, created_at
FROM audit.audit_log
WHERE tenant_id = #{tenantId}

    AND user_id = #{userId}


    AND operation = #{operation}


    AND target_type = #{targetType}


    AND status = #{status}


    AND created_at >= #{dateFrom}


    AND created_at <= #{dateTo}

ORDER BY created_at DESC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*)
FROM audit.audit_log
WHERE tenant_id = #{tenantId}

    AND user_id = #{userId}


    AND operation = #{operation}


    AND target_type = #{targetType}


    AND status = #{status}


    AND created_at >= #{dateFrom}


    AND created_at <= #{dateTo}

SELECT id, tenant_id, user_id, username, operation, target_type, target_id, target_name,
       ip_address, user_agent, status, error_message, log_hash, previous_hash, created_at
FROM audit.audit_log
WHERE tenant_id = #{tenantId}
  AND created_at >= #{hourStart}
  AND created_at < #{hourEnd}
ORDER BY id ASC

SELECT id, tenant_id, hour_start, root_hash, log_count, created_at
FROM audit.audit_root_hash
WHERE tenant_id = #{tenantId}

    AND hour_start >= #{dateFrom}


    AND hour_start <= #{dateTo}

ORDER BY hour_start DESC
